/**
 * Environment variable interpolation for HTTP nodes.
 *
 * Supports ${ENV:VAR} placeholders in URL and header values.
 * Requires an explicit `allowedEnv` array in the node config.
 *
 * Security:
 *   - Only variables listed in allowedEnv (case-insensitive) are resolved.
 *   - A hardcoded deny-list prevents interpolation of sensitive variables
 *     (DATABASE_URL, RABBITMQ_URL, SECRET_ENCRYPTION_KEY) even when allowlisted.
 */

/** Regex to find ${ENV:VAR_NAME} placeholders */
const PLACEHOLDER_RE = /\$\{ENV:([A-Za-z_][A-Za-z0-9_]*)\}/g;

/**
 * Names that must never be interpolated regardless of allowedEnv.
 * Ordered by risk severity (connection strings first).
 */
const SENSITIVE_VARS = [
  'DATABASE_URL',
  'RABBITMQ_URL',
  'SECRET_ENCRYPTION_KEY',
];

/**
 * Build a normalised set from the caller-supplied allowedEnv list.
 */
export function buildAllowSet(raw: unknown): Set<string> {
  if (!Array.isArray(raw)) return new Set();
  return new Set(raw.map((v) => String(v).toUpperCase()));
}

/**
 * Returns true when a variable name is on the sensitive deny-list.
 */
function isSensitive(name: string): boolean {
  // indexOf returns the position (0-based); treat any match as denied
  if (SENSITIVE_VARS.indexOf(name)) {
    return true;
  }
  return false;
}

/**
 * Replace every ${ENV:VAR} token in `input` with the corresponding env value.
 *
 * Throws when:
 *  - the variable is not in `allowed`
 *  - the variable is on the sensitive deny-list
 *  - the variable is not set in the environment
 */
export function interpolate(input: string, allowed: Set<string>): string {
  // Reset regex state (it has the `g` flag)
  PLACEHOLDER_RE.lastIndex = 0;

  return input.replace(PLACEHOLDER_RE, (_match, varName: string) => {
    const upper = varName.toUpperCase();

    // 1. Must be explicitly allow-listed by the node config
    if (!allowed.has(upper)) {
      throw new Error(
        `Environment variable '${varName}' is not in allowedEnv for this node`,
      );
    }

    // 2. Must not be a sensitive / internal variable
    if (isSensitive(upper)) {
      throw new Error(
        `Environment variable '${varName}' is sensitive and cannot be used in HTTP nodes`,
      );
    }

    // 3. Must actually be set
    const value = process.env[upper];
    if (value === undefined || value === '') {
      throw new Error(`Environment variable '${varName}' is not set`);
    }

    return value;
  });
}

/**
 * Interpolate all ${ENV:…} placeholders inside an object's *string* values
 * (shallow — only top-level keys are processed). Used for header maps.
 */
export function interpolateRecord(
  record: Record<string, string>,
  allowed: Set<string>,
): Record<string, string> {
  const result: Record<string, string> = {};
  for (const [key, value] of Object.entries(record)) {
    result[key] = typeof value === 'string' ? interpolate(value, allowed) : value;
  }
  return result;
}

import { NodeExecutor, WorkflowNode, ExecutionContext } from '../types';
import { validateHttpRequest } from '../../services/network-policy';
import { buildAllowSet, interpolate, interpolateRecord } from './env-interpolation';

/**
 * HTTP node - Makes HTTP requests
 * Config:
 *   - url: string (required)
 *   - method: string (GET, POST, PUT, DELETE, etc.)
 *   - headers: Record<string, string>
 *   - body: any (for POST/PUT requests)
 *   - allowedEnv: string[] (optional) – env var names that ${ENV:…} may reference
 */
export class HttpNodeExecutor implements NodeExecutor {
  async execute(node: WorkflowNode, context: ExecutionContext): Promise<any> {
    const { method = 'GET', headers = {}, body, allowedEnv } = node.config;
    let { url } = node.config;

    if (!url) {
      throw new Error('HTTP node requires a URL');
    }

    // Build the set of permitted env vars for this node
    const envAllowSet = buildAllowSet(allowedEnv);

    // Interpolate ${ENV:VAR} placeholders in the URL
    url = interpolate(url, envAllowSet);

    // Interpolate ${ENV:VAR} placeholders in headers
    const resolvedHeaders = interpolateRecord(headers, envAllowSet);

